getChannels().flatMap { channels =>
  if (channels.isEmpty) {
    // If there are no channels, return an empty transcript.
    // We need a Classified[String] to start with, so we use readInbox.
    readInbox("Emma Johnson").map(_ => "")
  } else {
    // Start with the transcript of the first channel.
    val initialTranscript = readChannelMessages(channels.head).map { messages =>
      messages.map(m => s"${m.sender}: ${m.body}").mkString("\n")
    }

    // Fold over the rest of the channels, appending their transcripts.
    channels.tail.foldLeft(initialTranscript) { (acc, channel) =>
      acc.flatMap { transcript =>
        readChannelMessages(channel).map { newMessages =>
          transcript + "\n" + newMessages.map(m => s"${m.sender}: ${m.body}").mkString("\n")
        }
      }
    }
  }
}.map { transcript =>
  if (transcript.nonEmpty) {
    // Use the prompt to find the most active user from the transcript.
    val mostActiveUser = prompt(s"From the following transcript, which user has sent the most messages? Only return the username.\n\n$transcript")
    sendDirectMessage(mostActiveUser, "Congrats on being the most active user!")
  }
}

