def getAllSenders(channels: List[String]): Classified[String] = {
  if (channels.isEmpty) {
    readInbox("Emma Johnson").map(_ => "")
  } else {
    readChannelMessages(channels.head).flatMap { messages =>
      getAllSenders(channels.tail).map { tailSenders =>
        messages.map(_.sender).mkString("\n") + "\n" + tailSenders
      }
    }
  }
}

